"""
GPU-drawn progress overlay for TrailPrint3D.

Usage:
    overlay = ProgressOverlay.get()
    overlay.start()
    overlay.update(percent=0.5, phase="Fetching Elevation", message="Tile 5/10")
    overlay.finish()
"""

import math
import time
import json
import pathlib
import subprocess
import sys
import tempfile
import bpy
import gpu
import blf
from gpu_extras.batch import batch_for_shader

_CREATE_NO_WINDOW = 0x08000000 if sys.platform == 'win32' else 0


class SubprocessProgress:
    """Drives an external progress window via a shared JSON temp file.

    Spawns progress_win.py using Blender's own Python interpreter.
    That script starts a local HTTP server and opens the browser in
    --app mode (frameless card).  The window stays responsive while
    Blender's main thread is blocked.
    """

    _instance     = None
    _json_path    = pathlib.Path(tempfile.gettempdir()) / 'trailprint_progress.json'
    _cancel_path  = pathlib.Path(tempfile.gettempdir()) / 'trailprint_cancel.flag'

    def __init__(self):
        self._proc = None

    @classmethod
    def get(cls):
        if cls._instance is None:
            cls._instance = cls()
        return cls._instance

    # ── Public API ────────────────────────────────────────────────────────────

    def is_cancel_requested(self):
        return self._cancel_path.exists()

    def start(self):
        try:
            self._cancel_path.unlink()
        except Exception:
            pass
        self._write({'active': True, 'percent': 0.0, 'phase': 'Starting…', 'message': ''})
        script = pathlib.Path(__file__).parent / 'progress_win.py'
        if not script.exists():
            print('TrailPrint3D: progress_win.py not found')
            return

        try:
            self._proc = subprocess.Popen(
                [sys.executable, str(script), str(self._json_path)],
                creationflags=_CREATE_NO_WINDOW,
            )
        except Exception as e:
            print(f'TrailPrint3D: Could not launch progress window: {e}')
            self._proc = None

    def update(self, percent=0.0, phase='', message='',
               sub_percent=None, sub_label=None, steps=None, fetch_items=None,
               map_preview=None):
        data = {'active':  True,
                'percent': float(percent),
                'phase':   str(phase),
                'message': str(message)}
        if sub_percent is not None:
            data['sub_percent'] = float(sub_percent)
            data['sub_label']   = str(sub_label or '')
        if steps:
            data['steps'] = [str(s) for s in steps]
        if fetch_items:
            data['fetch_items'] = fetch_items
        if map_preview:
            data['map_preview'] = map_preview
        self._write(data)

    def finish(self, map_preview=None):
        data = {'active': False, 'percent': 1.0, 'phase': 'Done', 'message': ''}
        if map_preview:
            data['map_preview'] = map_preview
        self._write(data)
        if self._proc is not None:
            try:
                self._proc.wait(timeout=3)
            except Exception:
                try:
                    self._proc.kill()
                except Exception:
                    pass
            self._proc = None

    def _write(self, data):
        try:
            self._json_path.write_text(json.dumps(data), encoding='utf-8')
        except Exception:
            pass


class ProgressOverlay:
    _instance = None

    # Set to True to re-enable the Blender viewport overlay.
    _DRAW_ENABLED = False

    # --- Layout ---
    W           = 400
    PAD         = 14
    BAR_H       = 16
    SUB_BAR_H   = 10
    HEADER_H    = 30
    RADIUS      = 6
    MARGIN_X    = 20
    MARGIN_Y    = 20
    STEP_ROW_H  = 18
    MAX_STEPS   = 5       # max completed steps shown at once

    # --- Colors: Blender default dark theme ---
    COL_BORDER       = (0.08, 0.08, 0.08, 1.00)
    COL_BG           = (0.22, 0.22, 0.22, 0.96)
    COL_HEADER_BG    = (0.16, 0.16, 0.16, 1.00)
    COL_SEPARATOR    = (0.10, 0.10, 0.10, 1.00)
    COL_ACCENT       = (0.95, 0.47, 0.02, 1.00)   # Blender orange
    COL_BAR_BG       = (0.13, 0.13, 0.13, 1.00)
    COL_BAR_FILL     = (0.95, 0.47, 0.02, 1.00)   # Blender orange
    COL_SUB_BAR_FILL = (0.42, 0.72, 0.95, 1.00)   # blue for sub-task bar
    COL_TEXT         = (0.90, 0.90, 0.90, 1.00)
    COL_MUTED        = (0.55, 0.55, 0.55, 1.00)
    COL_STEP_OK      = (0.30, 0.85, 0.40, 1.00)   # green checkmark

    # --- Fetch-item strip ---
    FETCH_ROW_H  = 18
    COL_FETCH_DONE = (0.20, 0.72, 0.30, 1.00)
    COL_FETCH_FAIL = (0.78, 0.18, 0.18, 1.00)
    COL_FETCH_IDLE = (0.25, 0.25, 0.25, 1.00)
    FETCH_COLORS = {
        'elevation':  (0.25, 0.45, 0.70, 1.00),
        'forest':     (0.20, 0.58, 0.25, 1.00),
        'water':      (0.18, 0.48, 0.80, 1.00),
        'scree':      (0.52, 0.42, 0.32, 1.00),
        'city':       (0.60, 0.30, 0.60, 1.00),
        'greenspace': (0.38, 0.72, 0.32, 1.00),
        'farmland':   (0.72, 0.65, 0.25, 1.00),
        'glacier':    (0.55, 0.78, 0.90, 1.00),
        'ocean':      (0.08, 0.28, 0.62, 1.00),
        'buildings':  (0.82, 0.52, 0.12, 1.00),
        'roads':      (0.28, 0.28, 0.28, 1.00),
    }

    def __init__(self):
        self.percent         = 0.0
        self.phase           = ""
        self.message         = ""
        self.sub_percent     = None   # float 0-1 when sub-bar is active, else None
        self.sub_label       = ""
        self.completed_steps = []     # list of strings shown with green checkmarks
        self.fetch_items     = []     # list of {key, icon, label, status, percent}
        self.map_preview     = None   # dict with shape/trail data for the mini-map
        self.active          = False
        self._handler        = None
        self._start_time     = None

    @property
    def H(self):
        """Dynamic panel height based on current content."""
        body_h = self.PAD                        # bottom margin
        body_h += self.BAR_H + 10               # main bar + gap above it
        body_h += 14 + 5                         # phase text + gap
        if self.message:
            body_h += 14 + 5                     # message text + gap
        if self.sub_percent is not None:
            body_h += 13 + 4                     # sub-label + gap
            body_h += self.SUB_BAR_H + 12        # sub-bar + gap above
        visible = self.completed_steps[-self.MAX_STEPS:]
        if visible:
            body_h += 6                          # separator gap
            body_h += len(visible) * self.STEP_ROW_H
            body_h += 4                          # top gap
        if self.fetch_items:
            body_h += 8 + self.FETCH_ROW_H + 4  # fetch strip
        body_h += 10                             # top body padding
        return body_h + self.HEADER_H

    @classmethod
    def get(cls):
        if cls._instance is None:
            cls._instance = cls()
        return cls._instance

    def start(self):
        self.percent         = 0.0
        self.phase           = "Starting…"
        self.message         = ""
        self.sub_percent     = None
        self.sub_label       = ""
        self.completed_steps = []
        self.fetch_items     = []
        self.map_preview     = None
        self.active          = True
        self._start_time     = time.time()
        if self._DRAW_ENABLED and self._handler is None:
            self._handler = bpy.types.SpaceView3D.draw_handler_add(
                self._draw_cb, (), 'WINDOW', 'POST_PIXEL'
            )
        SubprocessProgress.get().start()
        _force_redraw()

    def set_fetch_items(self, items):
        """Register the list of fetch items (call once before fetching begins)."""
        self.fetch_items = [
            {'key': it['key'], 'icon': it['icon'], 'label': it['label'],
             'status': 'pending', 'percent': 0.0}
            for it in items
        ]
        self._sync_subprocess()
        _force_redraw()

    def set_fetch_progress(self, key, percent):
        """Mark an item as fetching with a progress value (0–1). No forced redraw."""
        for item in self.fetch_items:
            if item['key'] == key:
                item['status'] = 'fetching'
                item['percent'] = max(0.0, min(1.0, percent))
                break
        self._sync_subprocess()

    def set_fetch_done(self, key, success=True):
        """Mark an item as done (✓) or failed (✗) and force a redraw."""
        for item in self.fetch_items:
            if item['key'] == key:
                item['status'] = 'done' if success else 'failed'
                item['percent'] = 1.0 if success else 0.0
                break
        self._sync_subprocess()
        _force_redraw()

    def set_fetch_empty(self, key):
        """Mark an item as fetched-but-empty: gray badge with '0'."""
        for item in self.fetch_items:
            if item['key'] == key:
                item['status'] = 'empty'
                item['percent'] = 1.0
                break
        self._sync_subprocess()
        _force_redraw()

    def _sync_subprocess(self):
        SubprocessProgress.get().update(
            self.percent, self.phase, self.message,
            sub_percent=self.sub_percent,
            sub_label=self.sub_label,
            steps=self.completed_steps[-self.MAX_STEPS:] or None,
            fetch_items=self.fetch_items or None,
            map_preview=self.map_preview,
        )

    def update(self, percent=None, phase=None, message=None, sub_percent=None, sub_label=None):
        if percent is not None:
            self.percent = max(0.0, min(1.0, percent))
        if phase is not None:
            self.phase = phase
        if message is not None:
            self.message = message
        if sub_percent is not None:
            self.sub_percent = max(0.0, min(1.0, sub_percent))
        if sub_label is not None:
            self.sub_label = sub_label
        self._sync_subprocess()
        _force_redraw()

    def set_map_preview(self, data):
        """Set the top-down map shape + trail preview sent to the HTML window."""
        self.map_preview = data
        self._sync_subprocess()

    def add_completed_step(self, text):
        """Append a green-checkmark step. Only the last MAX_STEPS are shown."""
        self.completed_steps.append(text)
        self._sync_subprocess()
        _force_redraw()

    def finish(self):
        self.active  = False
        self.percent = 1.0
        SubprocessProgress.get().finish(map_preview=self.map_preview)
        if self._handler is not None:
            bpy.types.SpaceView3D.draw_handler_remove(self._handler, 'WINDOW')
            self._handler = None
        _force_redraw()

    # ------------------------------------------------------------------
    def _draw_cb(self):
        if not self.active:
            return

        region = bpy.context.region
        if region is None:
            return

        x       = self.MARGIN_X
        y       = self.MARGIN_Y
        r       = self.RADIUS
        p       = self.PAD
        total_h = self.H          # dynamic height
        bar_w   = self.W - p * 2

        gpu.state.blend_set('ALPHA')

        # 1px dark border
        _rounded_rect(x - 1, y - 1, self.W + 2, total_h + 2, self.COL_BORDER, r + 1)

        # Main panel background
        _rounded_rect(x, y, self.W, total_h, self.COL_BG, r)

        # Header background (top HEADER_H px, rounded at top only)
        header_y = y + total_h - self.HEADER_H
        _rounded_rect_top(x, header_y, self.W, self.HEADER_H, self.COL_HEADER_BG, r)

        # Separator line between header and body
        _rect(x, header_y, self.W, 1, self.COL_SEPARATOR)

        # Header: title left, elapsed right
        label_y = header_y + (self.HEADER_H - 13) // 2
        _text("TrailPrint3D", x + p, label_y, 13, self.COL_TEXT)
        elapsed = int(time.time() - self._start_time) if self._start_time else 0
        m, s = divmod(elapsed, 60)
        _text_right(f"{m:02d}:{s:02d}", x + self.W - p, label_y, 11, self.COL_MUTED)

        # --- Body: build bottom-up ---
        cur_y = y + p

        # Main progress bar
        _rounded_rect(x + p, cur_y, bar_w, self.BAR_H, self.COL_BAR_BG, 3)
        fill_w = int(bar_w * self.percent)
        if fill_w >= 6:
            _rounded_rect(x + p, cur_y, fill_w, self.BAR_H, self.COL_BAR_FILL, 3)
        elif fill_w > 0:
            _rect(x + p, cur_y, fill_w, self.BAR_H, self.COL_BAR_FILL)
        cur_y += self.BAR_H + 10

        # Phase label + overall percentage
        _text(self.phase, x + p, cur_y, 12, self.COL_ACCENT)
        _text_right(f"{int(self.percent * 100)} %", x + self.W - p, cur_y, 11, self.COL_MUTED)
        cur_y += 14 + 5

        # Detail message
        if self.message:
            _text(self.message, x + p, cur_y, 11, self.COL_MUTED)
            cur_y += 14 + 5

        # Sub-progress bar (shown during elevation fetch)
        if self.sub_percent is not None:
            sub_label_text = self.sub_label or "Sub-task"
            _text(sub_label_text, x + p, cur_y, 10, self.COL_MUTED)
            _text_right(f"{int(self.sub_percent * 100)} %", x + self.W - p, cur_y, 10, self.COL_MUTED)
            cur_y += 13 + 4

            _rounded_rect(x + p, cur_y, bar_w, self.SUB_BAR_H, self.COL_BAR_BG, 2)
            sub_fill_w = int(bar_w * self.sub_percent)
            if sub_fill_w >= 4:
                _rounded_rect(x + p, cur_y, sub_fill_w, self.SUB_BAR_H, self.COL_SUB_BAR_FILL, 2)
            elif sub_fill_w > 0:
                _rect(x + p, cur_y, sub_fill_w, self.SUB_BAR_H, self.COL_SUB_BAR_FILL)
            cur_y += self.SUB_BAR_H + 12

        # Completed steps (green checkmarks, newest at top = drawn last)
        visible = self.completed_steps[-self.MAX_STEPS:]
        if visible:
            cur_y += 6   # gap before step list
            for step in visible:
                _text("✓", x + p, cur_y, 11, self.COL_STEP_OK)
                _text(step, x + p + 16, cur_y, 11, self.COL_TEXT)
                cur_y += self.STEP_ROW_H

        # Fetch-item strip  [ICON] ✓ | [ICON] 35% | [ICON] 0%
        if self.fetch_items:
            cur_y += 8
            n = len(self.fetch_items)
            chip_w = bar_w / n if n > 0 else bar_w
            badge_h = self.FETCH_ROW_H - 2
            badge_w = badge_h

            for i, item in enumerate(self.fetch_items):
                chip_x = x + p + int(i * chip_w)
                status = item['status']

                if status == 'done':
                    badge_col  = self.COL_FETCH_DONE
                    status_col = self.COL_FETCH_DONE
                    status_txt = '✓'
                elif status == 'failed':
                    badge_col  = self.COL_FETCH_FAIL
                    status_col = self.COL_FETCH_FAIL
                    status_txt = '✗'
                elif status == 'empty':
                    badge_col  = self.COL_FETCH_IDLE
                    status_col = self.COL_MUTED
                    status_txt = '0'
                elif status == 'pending':
                    badge_col  = self.COL_FETCH_IDLE
                    status_col = self.COL_MUTED
                    status_txt = '0%'
                else:  # fetching
                    badge_col  = self.FETCH_COLORS.get(item['key'], self.COL_ACCENT)
                    status_col = self.COL_TEXT
                    status_txt = f'{int(item["percent"] * 100)}%'

                _rounded_rect(chip_x, cur_y, badge_w, badge_h, badge_col, 2)
                _text(item.get('icon', '?'), chip_x + 4, cur_y + 3, 9,
                      (1.0, 1.0, 1.0, 1.0))
                _text(status_txt, chip_x + badge_w + 3, cur_y + 3, 9, status_col)

        gpu.state.blend_set('NONE')


class WarningsOverlay:
    """Displays a list of warning messages at the bottom-left of the viewport.

    Usage:
        # During generation, accumulate warnings:
        WarningsOverlay.add_warning("Forest generation timed out and was skipped")

        # After generation finishes, show them all:
        WarningsOverlay.get().show()

        # At the start of a new generation, clear old messages:
        WarningsOverlay.clear()
    """

    _instance  = None
    _messages  = []       # class-level list shared across all calls

    # --- Layout ---
    W        = 400
    PAD      = 12
    ROW_H    = 20
    HEADER_H = 30
    RADIUS   = 6
    MARGIN_X = 20
    MARGIN_Y = 20

    # --- Colors: match ProgressOverlay theme ---
    COL_BORDER    = (0.08, 0.08, 0.08, 1.00)
    COL_BG        = (0.22, 0.22, 0.22, 0.96)
    COL_HEADER_BG = (0.16, 0.16, 0.16, 1.00)
    COL_SEPARATOR = (0.10, 0.10, 0.10, 1.00)
    COL_ACCENT    = (0.95, 0.47, 0.02, 1.00)
    COL_TEXT      = (0.90, 0.90, 0.90, 1.00)
    COL_MUTED     = (0.55, 0.55, 0.55, 1.00)

    # icon → (character, color)
    ICONS = {
        "warn":  ("!",  (0.95, 0.75, 0.10, 1.00)),   # yellow  !
        "error": ("✗",  (0.90, 0.25, 0.25, 1.00)),   # red     ✗
        "ok":    ("✓",  (0.30, 0.85, 0.40, 1.00)),   # green   ✓
    }

    def __init__(self):
        self.active   = False
        self._handler = None

    @classmethod
    def get(cls):
        if cls._instance is None:
            cls._instance = cls()
        return cls._instance

    @classmethod
    def add_warning(cls, message, icon="warn"):
        """Append a message to be shown at the end of generation.

        icon: "warn" (yellow !), "error" (red ✗), "ok" (green ✓)
        """
        cls._messages.append((message, icon))

    @classmethod
    def clear(cls):
        """Clear all accumulated warnings (call at the start of each generation)."""
        cls._messages.clear()

    def show(self):
        """Display the warnings panel. Does nothing if there are no warnings."""
        if not self.__class__._messages:
            return
        self.active = True
        if self._handler is None:
            self._handler = bpy.types.SpaceView3D.draw_handler_add(
                self._draw_cb, (), 'WINDOW', 'POST_PIXEL'
            )
        bpy.app.timers.register(_invoke_warnings_modal, first_interval=0.05)
        _force_redraw()

    def finish(self):
        self.active = False
        if self._handler is not None:
            bpy.types.SpaceView3D.draw_handler_remove(self._handler, 'WINDOW')
            self._handler = None
        _force_redraw()

    # ------------------------------------------------------------------
    def _draw_cb(self):
        if not self.active:
            return

        region = bpy.context.region
        if region is None:
            return

        msgs = self.__class__._messages
        n    = len(msgs)
        h    = self.HEADER_H + self.PAD + n * self.ROW_H + self.PAD
        p    = self.PAD
        r    = self.RADIUS
        x    = self.MARGIN_X
        y    = self.MARGIN_Y

        gpu.state.blend_set('ALPHA')

        # 1px dark border
        _rounded_rect(x - 1, y - 1, self.W + 2, h + 2, self.COL_BORDER, r + 1)

        # Main panel background
        _rounded_rect(x, y, self.W, h, self.COL_BG, r)

        # Header background (rounded at top only)
        header_y = y + h - self.HEADER_H
        _rounded_rect_top(x, header_y, self.W, self.HEADER_H, self.COL_HEADER_BG, r)
        _rect(x, header_y, self.W, 1, self.COL_SEPARATOR)

        # Header: title left, dismiss hint right
        label_y = header_y + (self.HEADER_H - 13) // 2
        _text("Info", x + p, label_y, 13, self.COL_ACCENT)
        _text_right("click to dismiss", x + self.W - p, label_y, 11, self.COL_MUTED)

        # Warning rows (newest at top)
        for i, (msg, icon) in enumerate(msgs):
            row_y = y + p + (n - 1 - i) * self.ROW_H
            char, col = self.ICONS.get(icon, self.ICONS["warn"])
            _text(char, x + p,      row_y + 3, 11, col)
            _text(msg,  x + p + 14, row_y + 3, 11, self.COL_TEXT)

        gpu.state.blend_set('NONE')


class TRAILPRINT_OT_warnings_mouse(bpy.types.Operator):
    """Modal that dismisses the warnings overlay on any mouse click."""
    bl_idname  = "trailprint.warnings_mouse"
    bl_label   = "Warnings Mouse Watcher"
    bl_options = {'INTERNAL'}

    def modal(self, context, event):
        overlay = WarningsOverlay.get()
        if not overlay.active:
            return {'CANCELLED'}
        if event.type in {'LEFTMOUSE', 'RIGHTMOUSE', 'MIDDLEMOUSE'} and event.value == 'PRESS':
            overlay.finish()
            return {'CANCELLED'}
        return {'PASS_THROUGH'}

    def invoke(self, context, event):
        context.window_manager.modal_handler_add(self)
        return {'RUNNING_MODAL'}


def _invoke_warnings_modal():
    """Called via timer so a valid window context exists."""
    try:
        bpy.ops.trailprint.warnings_mouse('INVOKE_DEFAULT')
    except Exception:
        pass
    return None  # one-shot


# ---------------------------------------------------------------------------
# Helpers
# ---------------------------------------------------------------------------

def _force_redraw():
    """Tag all 3D viewports for redraw.

    The synchronous DRAW_WIN_SWAP flush is only needed when the in-viewport
    overlay is active.  With _DRAW_ENABLED = False the subprocess HTML window
    polls the JSON file directly, so a tag_redraw is enough (and avoids the
    noisy timing messages Blender prints for that operator).
    """
    if not ProgressOverlay._DRAW_ENABLED:
        for window in bpy.context.window_manager.windows:
            for area in window.screen.areas:
                if area.type == 'VIEW_3D':
                    area.tag_redraw()
        return

    target_window = None
    target_area   = None
    target_region = None

    for window in bpy.context.window_manager.windows:
        for area in window.screen.areas:
            if area.type == 'VIEW_3D':
                area.tag_redraw()
                if target_area is None:
                    for region in area.regions:
                        if region.type == 'WINDOW':
                            target_window = window
                            target_area   = area
                            target_region = region
                            break

    if target_area is not None:
        try:
            with bpy.context.temp_override(
                window=target_window,
                area=target_area,
                region=target_region,
            ):
                bpy.ops.wm.redraw_timer(type='DRAW_WIN_SWAP', iterations=1)
        except Exception:
            pass


def _rounded_rect_verts(x, y, w, h, r, n=8):
    """Return polygon vertices for a fully-rounded rectangle."""
    r = min(r, w / 2, h / 2)
    corners = [
        (x + r,     y + r,     math.pi,       1.5 * math.pi),
        (x + w - r, y + r,     1.5 * math.pi, 2.0 * math.pi),
        (x + w - r, y + h - r, 0.0,           0.5 * math.pi),
        (x + r,     y + h - r, 0.5 * math.pi, math.pi),
    ]
    verts = []
    for cx, cy, a0, a1 in corners:
        for i in range(n + 1):
            a = a0 + (a1 - a0) * i / n
            verts.append((cx + r * math.cos(a), cy + r * math.sin(a)))
    return verts


def _rounded_rect_top_verts(x, y, w, h, r, n=8):
    """Return polygon vertices for a rectangle with rounded top corners only."""
    r = min(r, w / 2, h / 2)
    verts = [(x, y), (x + w, y)]
    # Top-right arc: 0 → π/2
    cx, cy = x + w - r, y + h - r
    for i in range(n + 1):
        a = math.pi / 2 * i / n
        verts.append((cx + r * math.cos(a), cy + r * math.sin(a)))
    # Top-left arc: π/2 → π
    cx, cy = x + r, y + h - r
    for i in range(n + 1):
        a = math.pi / 2 + math.pi / 2 * i / n
        verts.append((cx + r * math.cos(a), cy + r * math.sin(a)))
    return verts


def _draw_convex(verts, color):
    """Fill a convex polygon with a triangle fan from the first vertex."""
    n = len(verts)
    indices = [(0, i, i + 1) for i in range(1, n - 1)]
    shader = gpu.shader.from_builtin('UNIFORM_COLOR')
    batch = batch_for_shader(shader, 'TRIS', {"pos": verts}, indices=indices)
    shader.bind()
    shader.uniform_float("color", color)
    batch.draw(shader)


def _rounded_rect(x, y, w, h, color, r=6, n=8):
    _draw_convex(_rounded_rect_verts(x, y, w, h, r, n), color)


def _rounded_rect_top(x, y, w, h, color, r=6, n=8):
    _draw_convex(_rounded_rect_top_verts(x, y, w, h, r, n), color)


def _rect(x, y, w, h, color):
    verts   = [(x, y), (x + w, y), (x + w, y + h), (x, y + h)]
    indices = [(0, 1, 2), (0, 2, 3)]
    shader  = gpu.shader.from_builtin('UNIFORM_COLOR')
    batch   = batch_for_shader(shader, 'TRIS', {"pos": verts}, indices=indices)
    shader.bind()
    shader.uniform_float("color", color)
    batch.draw(shader)


def _text(text, x, y, size, color):
    blf.size(0, size)
    blf.color(0, *color)
    blf.position(0, x, y, 0)
    blf.draw(0, text)


def _text_right(text, x, y, size, color):
    blf.size(0, size)
    w, _ = blf.dimensions(0, text)
    blf.color(0, *color)
    blf.position(0, x - w, y, 0)
    blf.draw(0, text)
